
-- Padronizar nome existente para o formato em maiúsculas
UPDATE public.schools SET name = 'CETI MANOEL RICARDO' WHERE name = 'CETI Manoel Ricardo';
UPDATE public.profiles SET school = 'CETI MANOEL RICARDO' WHERE school = 'CETI Manoel Ricardo';
UPDATE public.clubs SET school = 'CETI MANOEL RICARDO' WHERE school = 'CETI Manoel Ricardo';

-- Atualizar defaults
ALTER TABLE public.profiles ALTER COLUMN school SET DEFAULT 'CETI MANOEL RICARDO';
ALTER TABLE public.clubs ALTER COLUMN school SET DEFAULT 'CETI MANOEL RICARDO';

-- Atualizar trigger de novo usuário para usar o novo default
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  _email text;
  _school text;
BEGIN
  _email := lower(NEW.email);

  IF _email IS NULL OR (
    _email NOT LIKE '%@aluno.edu.pi.gov.br'
    AND _email NOT LIKE '%@professor.edu.pi.gov.br'
  ) THEN
    RAISE EXCEPTION 'Apenas e-mails institucionais da Seduc-PI são permitidos.'
      USING ERRCODE = 'check_violation';
  END IF;

  _school := COALESCE(NULLIF(NEW.raw_user_meta_data->>'school', ''), 'CETI MANOEL RICARDO');

  INSERT INTO public.profiles (id, user_id, name, username, school)
  VALUES (
    gen_random_uuid(),
    NEW.id,
    COALESCE(NEW.raw_user_meta_data->>'name', split_part(NEW.email, '@', 1)),
    COALESCE(NEW.raw_user_meta_data->>'username', split_part(NEW.email, '@', 1)),
    _school
  );

  IF _email LIKE '%@professor.edu.pi.gov.br' THEN
    INSERT INTO public.user_roles (user_id, role)
    VALUES (NEW.id, 'admin'::app_role)
    ON CONFLICT DO NOTHING;
  ELSE
    INSERT INTO public.user_roles (user_id, role)
    VALUES (NEW.id, 'user'::app_role)
    ON CONFLICT DO NOTHING;
  END IF;

  RETURN NEW;
END;
$$;

